# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(transactions, accounts):
    """
    Process financial transactions and update account balances.
    
    Args:
        transactions (list): List of transaction dictionaries with keys 'account_id', 'amount', 'type'
        accounts (dict): Dictionary of account dictionaries with keys 'account_id', 'balance'
    
    Returns:
        dict: Updated accounts dictionary
    """
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        transaction_type = transaction['type']  # 'debit' or 'credit'
        
        if account_id in accounts:
            if transaction_type == 'debit':
                accounts[account_id]['balance'] -= amount
            elif transaction_type == 'credit':
                accounts[account_id]['balance'] += amount
    
    return accounts

